mapper.select:
SELECT e.UNIT_NAME AS unitName, d.DEPT_NAME AS useOrgName, e.EQUIP_SMALL_CATEGORY_NAME AS equipSmallCategoryName, e.EQUIP_NAME AS equipName, e.EQUIP_CODE AS equipCode, e.SPECIFIC_CODE AS specificCode, e.MODEL_NUMBER AS modelNumber, s.PARTICULAR_REGISTRATION_CODE AS particularRegistrationCode, s.RELEASE_DATE AS releaseDate, s.EXPIRE_DATE AS expireDate, s.VALID_DATE AS validDate FROM E_M_EQPT_INFO e INNER JOIN E_M_EQPT_SPECIAL s ON e.ID = s.EQUIP_ID AND s.DEL_FLAG = 0 LEFT JOIN SYS_DEPT d ON e.USE_ORG_ID = d.ID
e.DEL_FLAG = 0 AND e.IS_PARTICULAR = 1
AND e.EQUIP_NAME LIKE #{equipNamePattern}
AND e.EQUIP_CODE LIKE #{equipCodePattern}
AND s.PARTICULAR_REGISTRATION_CODE LIKE #{particularRegistrationCodePattern}
ORDER BY s.EXPIRE_DATE ASC
